const raw = $input.first().json;

// Geozo API response: { result: { data: [...], pagination: {...}, total_result: {...} } }
// or sometimes wrapped differently by n8n HTTP node
let statsData = [];

if (raw?.result?.data && Array.isArray(raw.result.data)) {
  statsData = raw.result.data;
} else if (raw?.data?.result?.data && Array.isArray(raw.data.result.data)) {
  statsData = raw.data.result.data;
} else if (raw?.data && Array.isArray(raw.data)) {
  statsData = raw.data;
} else if (Array.isArray(raw)) {
  statsData = raw;
}

if (statsData.length === 0) {
  // Return a single item so workflow continues but DB gets nothing
  return [{ json: { _empty: true, _raw_keys: Object.keys(raw || {}), _raw_sample: JSON.stringify(raw).substring(0, 500) } }];
}

const results = statsData
  .filter(d => d.ad_id && d.ad_id > 0)
  .map(d => {
    const spend = parseFloat(d.money) || parseFloat(d.total_expenses) || 0;
    const revenue = parseFloat(d.postbacks_confirmed_money) || 0;
    const clicks = parseInt(d.clicks_count) || 0;
    const shows = parseInt(d.shows_count) || 0;
    const confirmedShows = parseInt(d.confirmed_shows_count) || 0;
    const postbacks = parseInt(d.postbacks_total_count) || 0;

    const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;
    const profit = revenue - spend;
    const ctr = shows > 0 ? (clicks / shows * 100) : 0;
    const cpc = clicks > 0 ? (spend / clicks) : 0;

    // Date: from API grouping, or fallback to today
    const date = d.date || $now.toFormat('yyyy-MM-dd');

    let status = 'HOLD';
    let alertLevel = null;

    if (roi > 100) {
      status = 'PROFIT_HIGH';
      alertLevel = 'green';
    } else if (roi > 50) {
      status = 'PROFIT';
      alertLevel = 'green';
    } else if (roi > 0) {
      status = 'MARGINAL';
    } else if (roi > -30) {
      status = 'LOSING';
      alertLevel = 'yellow';
    } else if (roi > -50) {
      status = 'BURNING';
      alertLevel = 'orange';
    } else if (spend > 3) {
      status = 'CRITICAL';
      alertLevel = 'red';
    }

    return {
      json: {
        ad_id: parseInt(d.ad_id),
        date: date,
        shows: shows,
        confirmed_shows: confirmedShows,
        clicks: clicks,
        money: Math.round(spend * 10000) / 10000,
        postbacks_count: postbacks,
        postbacks_confirmed_money: Math.round(revenue * 10000) / 10000,
        ctr: Math.round(ctr * 10000) / 10000,
        cpc: Math.round(cpc * 10000) / 10000,
        roi: Math.round(roi * 100) / 100,
        profit: Math.round(profit * 10000) / 10000,
        status: status,
        alertLevel: alertLevel
      }
    };
  });

return results.length > 0 ? results : [{ json: { _empty: true } }];

const items = $input.all();
const alerts = items.filter(i => i.json.alertLevel);

if (alerts.length === 0) return [];

// Only alert for today's stats
const today = $now.toFormat('yyyy-MM-dd');
const todayAlerts = alerts.filter(i => i.json.date === today);
if (todayAlerts.length === 0) return [];

const redAlerts = todayAlerts.filter(i => i.json.alertLevel === 'red');
const greenAlerts = todayAlerts.filter(i => i.json.alertLevel === 'green');
const yellowAlerts = todayAlerts.filter(i => i.json.alertLevel === 'yellow' || i.json.alertLevel === 'orange');

let message = `📊 GEOZO STATS ${$now.toFormat('dd.MM.yyyy HH:mm')}\n\n`;

if (redAlerts.length > 0) {
  message += `🔴 КРИТИЧЕСКИЕ (ROI < -50%, расход > $3):\n`;
  redAlerts.slice(0, 5).forEach(a => {
    message += `  Ad #${a.json.ad_id}: ROI ${a.json.roi}%, Расход $${a.json.money}, P&L $${a.json.profit}\n`;
  });
  message += `\n`;
}

if (yellowAlerts.length > 0) {
  message += `🟡 ВНИМАНИЕ (убыток):\n`;
  yellowAlerts.slice(0, 5).forEach(a => {
    message += `  Ad #${a.json.ad_id}: ROI ${a.json.roi}%, Расход $${a.json.money}\n`;
  });
  message += `\n`;
}

if (greenAlerts.length > 0) {
  message += `🟢 ПРИБЫЛЬ:\n`;
  greenAlerts.slice(0, 5).forEach(a => {
    message += `  Ad #${a.json.ad_id}: ROI ${a.json.roi}%, P&L $${a.json.profit}\n`;
  });
}

message += `\n📈 Всего объявлений за сегодня: ${todayAlerts.length}`;
message += `\n🔴 Крит: ${redAlerts.length} | 🟡 Внимание: ${yellowAlerts.length} | 🟢 Прибыль: ${greenAlerts.length}`;

return [{ json: { message } }];
